const body = $input.first().json.body || $input.first().json;
const type = body.type || 'info';
const CHAT_ID = '8631035943';
const icons = {e2e:'\ud83c\udfe5',error:'\ud83d\udea8',deploy:'\ud83d\ude80',info:'\ud83d\udce1'};
const icon = icons[type] || '\ud83d\udce1';
const now = new Date().toLocaleString('en-US',{timeZone:'America/New_York'});
let text = icon + ' *GDA Command* \u2022 ' + now + '\n';
if (type === 'e2e') {
  const pr = body.pass_rate || '??';
  const p = body.passed || 0;
  const f = body.failed || 0;
  const e = body.errors || 0;
  const status = parseInt(pr) >= 90 ? '\u2705' : parseInt(pr) >= 70 ? '\u26a0\ufe0f' : '\u274c';
  text += status + ' E2E: ' + pr + ' pass rate\n';
  text += '\u2705 ' + p + ' passed | \u274c ' + f + ' failed | \u26a0\ufe0f ' + e + ' errors';
} else if (type === 'error') {
  text += '\u26a0\ufe0f Workflow Error\n';
  text += '*WF:* ' + (body.workflow_name || 'Unknown') + '\n';
  text += '*Node:* ' + (body.error_node || '--') + '\n';
  text += '`' + (body.error_message || 'No message').substring(0, 200) + '`';
} else if (type === 'deploy') {
  const ok = body.success !== false;
  text += (ok ? '\u2705' : '\u274c') + ' Deploy: ' + (body.message || body.msg || 'completed') + '\n';
  if (body.lines) text += '\ud83d\udcc4 ' + body.lines + ' lines';
} else {
  text += body.message || body.text || JSON.stringify(body).substring(0, 300);
}
return [{json:{text, chatId: CHAT_ID}}];
